"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";

type HashResult = {
    fileName: string;
    fileSize: number;
    hashAlgorithm: string;
    hash: string;
    uploadedAt: string;
};

export default function CreateCase() {
    const router = useRouter();
    const { user, isLoading: authLoading } = useAuth();

    const [title, setTitle] = useState("");
    const [description, setDescription] = useState("");
    const [suspects, setSuspects] = useState("");
    const [inCharges, setInCharges] = useState("");
    const [witnesses, setWitnesses] = useState("");



    const [file, setFile] = useState<File | null>(null);
    const [evidence, setEvidence] = useState<HashResult[]>([]);
    const [isUploading, setIsUploading] = useState(false);

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const handleUploadEvidence = async () => {
        if (!file) return;

        setIsUploading(true);
        setError("");

        try {
            const formData = new FormData();
            formData.append("file", file);

            const res = await fetch("/api/upload", {
                method: "POST",
                body: formData,
            });

            if (!res.ok) {
                const data = await res.json();
                throw new Error(data.error || "Failed to upload evidence");
            }

            const data: HashResult = await res.json();
            setEvidence([...evidence, data]);
            setFile(null); // Reset selection
            
            // Note: In a real app we would clear the input file value too via a ref
        } catch (err: any) {
            setError(err.message || "Failed to generate hash");
            console.error(err);
        } finally {
            setIsUploading(false);
        }
    };

    if (authLoading) return <div className="p-8">Loading...</div>;
    if (!user) {
        router.push("/login");
        return null;
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        // Helper to split comma separated strings into arrays
        const toArray = (str: string) =>
            str.split(",").map(item => item.trim()).filter(item => item !== "");

        try {
            const response = await fetch("/api/cases", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    title,
                    description,
                    suspects: toArray(suspects),
                    inCharges: toArray(inCharges),
                    witnesses: toArray(witnesses),
                    evidence: evidence,
                }),
            });

            if (response.ok) {
                router.push("/dashboard");
            } else {
                const data = await response.json();
                setError(data.error || "Failed to create case");
            }
        } catch (err) {
            setError("An unexpected error occurred");
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container mx-auto p-8 max-w-2xl">
            <div className="flex items-center justify-between mb-6">
                <h1 className="text-3xl font-bold">Create New Case</h1>
                <Link href="/dashboard" className="text-blue-600 hover:underline">
                    &larr; Back to Dashboard
                </Link>
            </div>

            <div className="bg-white rounded-lg shadow-md p-6">
                {error && (
                    <div className="bg-red-100 text-red-700 p-3 rounded mb-4">
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    <div className="mb-4">
                        <label className="block text-gray-700 font-medium mb-2">
                            Case Title *
                        </label>
                        <input
                            type="text"
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                            className="w-full border rounded-md p-2 focus:ring-blue-500 focus:border-blue-500"
                            required
                        />
                    </div>

                    <div className="mb-4">
                        <label className="block text-gray-700 font-medium mb-2">
                            Description *
                        </label>
                        <textarea
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            className="w-full border rounded-md p-2 h-32 focus:ring-blue-500 focus:border-blue-500"
                            required
                        />
                    </div>

                    <div className="mb-4">
                        <label className="block text-gray-700 font-medium mb-2">
                            Suspects <span className="text-sm font-normal text-gray-500">(comma separated)</span>
                        </label>
                        <input
                            type="text"
                            value={suspects}
                            onChange={(e) => setSuspects(e.target.value)}
                            className="w-full border rounded-md p-2"
                            placeholder="John Doe, Jane Smith"
                        />
                    </div>

                    <div className="mb-4">
                        <label className="block text-gray-700 font-medium mb-2">
                            In-Charges <span className="text-sm font-normal text-gray-500">(comma separated)</span>
                        </label>
                        <input
                            type="text"
                            value={inCharges}
                            onChange={(e) => setInCharges(e.target.value)}
                            className="w-full border rounded-md p-2"
                            placeholder="Officer Smith, Detective Johnson"
                        />
                    </div>

                    <div className="mb-6">
                        <label className="block text-gray-700 font-medium mb-2">
                            Witnesses <span className="text-sm font-normal text-gray-500">(comma separated)</span>
                        </label>
                        <input
                            type="text"
                            value={witnesses}
                            onChange={(e) => setWitnesses(e.target.value)}
                            className="w-full border rounded-md p-2"
                            placeholder="Alice, Bob"
                        />
                    </div>

                    <div className="mb-6 border rounded-md p-4 bg-gray-50">
                        <label className="block text-gray-700 font-medium mb-2">
                            Evidence Upload
                        </label>
                        <p className="text-sm text-gray-500 mb-4">
                            Upload images or documents to generate a verifiable cryptographic hash.
                        </p>
                        
                        <div className="flex items-center gap-4 mb-4">
                            <input
                                type="file"
                                onChange={(e) => setFile(e.target.files?.[0] || null)}
                                className="block w-full text-sm text-slate-500
                                file:mr-4 file:py-2 file:px-4
                                file:rounded-full file:border-0
                                file:text-sm file:font-semibold
                                file:bg-blue-50 file:text-blue-700
                                hover:file:bg-blue-100"
                            />
                            <button
                                type="button"
                                onClick={handleUploadEvidence}
                                disabled={isUploading || !file}
                                className="bg-slate-800 text-white px-4 py-2 rounded-md hover:bg-slate-700 disabled:opacity-50 whitespace-nowrap"
                            >
                                {isUploading ? "Hashing..." : "Upload & Hash"}
                            </button>
                        </div>

                        {evidence.length > 0 && (
                            <div className="mt-4 space-y-3">
                                <p className="font-semibold text-sm">Attached Evidence ({evidence.length})</p>
                                {evidence.map((item, idx) => (
                                    <div key={idx} className="bg-white p-3 rounded border text-sm flex flex-col gap-1">
                                        <div className="flex justify-between">
                                            <span className="font-medium">{item.fileName}</span>
                                            <span className="text-xs text-gray-500">{(item.fileSize / 1024).toFixed(1)} KB</span>
                                        </div>
                                        <div className="bg-gray-100 p-2 rounded text-xs font-mono break-all mt-1">
                                            {item.hashAlgorithm}: {item.hash}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>


                    <div className="flex justify-end gap-4">
                        <Link
                            href="/dashboard"
                            className="px-4 py-2 text-gray-600 hover:text-gray-900"
                        >
                            Cancel
                        </Link>
                        <button
                            type="submit"
                            disabled={loading}
                            className="bg-blue-600 text-white px-6 py-2 rounded-md hover:bg-blue-700 disabled:opacity-50"
                        >
                            {loading ? "Creating..." : "Create Case"}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}
